async function cacheNavmesh(scene, navmeshData) {
  // Add version info for future compatibility
  const dataToCache = {
    version: '1.0',
    vertices: navmeshData.vertices,
    faces: navmeshData.faces,
    timestamp: Date.now()
  };

  return await scene.setFlag('routinglib', 'navmeshData', dataToCache);
}

function loadNavmeshFromCache(cachedData) {
  // Version check
  if (cachedData.version !== '1.0') {
    console.warn('Cached navmesh version mismatch, regenerating');
    return null;
  }

  // Initialize pathfinding with cached data
  const pathfindingZone = createPathfindingZone(cachedData.vertices, cachedData.faces);
  return pathfindingZone;
}
