// Debounce function to prevent multiple rapid updates
let navmeshUpdateTimeout = null;
const DEBOUNCE_MS = 500;

function scheduleNavmeshUpdate() {
  if (navmeshUpdateTimeout) clearTimeout(navmeshUpdateTimeout);

  navmeshUpdateTimeout = setTimeout(async () => {
    await updateNavmesh();
    navmeshUpdateTimeout = null;
  }, DEBOUNCE_MS);
}

async function updateNavmesh() {
  const scene = game.scenes.current;
  const walls = canvas.walls.documents.filter(w => w.ds !== 2); // Filter out open doors

  try {
    const navmeshBuilder = new NavmeshBuilder();
    const navmeshData = await navmeshBuilder.buildNavmesh(walls, canvas.dimensions);

    // Update cache
    await scene.setFlag('routinglib', 'navmeshData', navmeshData);

    // Update active pathfinding
    updatePathfindingZone(navmeshData);

    console.log('Navmesh updated successfully');
  } catch (error) {
    console.error('Failed to update navmesh:', error);
  }
}

// Hook into wall modification events
Hooks.on('createWall', scheduleNavmeshUpdate);
Hooks.on('updateWall', scheduleNavmeshUpdate);
Hooks.on('deleteWall', scheduleNavmeshUpdate);
