class EnhancedPathfinder extends THREE.Pathfinding {
  constructor() {
    super();
    this.portalWidths = {}; // Cache of portal widths by zone
  }

  setZoneData(zoneName, zoneData) {
    const zone = super.setZoneData(zoneName, zoneData);

    // Calculate and cache portal widths
    this.calculatePortalWidths(zoneName, zoneData);

    return zone;
  }

  calculatePortalWidths(zoneName, zoneData) {
    const portalWidths = {};
    const vertices = zoneData.vertices;

    // For each triangle in the navmesh
    for (let i = 0; i < zoneData.faces.length; i += 3) {
      const a = zoneData.faces[i] * 3;
      const b = zoneData.faces[i + 1] * 3;
      const c = zoneData.faces[i + 2] * 3;

      // Get vertex positions
      const vA = new THREE.Vector3(vertices[a], vertices[a + 1], vertices[a + 2]);
      const vB = new THREE.Vector3(vertices[b], vertices[b + 1], vertices[b + 2]);
      const vC = new THREE.Vector3(vertices[c], vertices[c + 1], vertices[c + 2]);

      // Calculate edge lengths (portal widths)
      const edgeAB = vA.distanceTo(vB);
      const edgeBC = vB.distanceTo(vC);
      const edgeCA = vC.distanceTo(vA);

      // Store with a unique key for each edge
      portalWidths[`${Math.min(a, b)}_${Math.max(a, b)}`] = edgeAB;
      portalWidths[`${Math.min(b, c)}_${Math.max(b, c)}`] = edgeBC;
      portalWidths[`${Math.min(c, a)}_${Math.max(c, a)}`] = edgeCA;
