1. Create a separate JavaScript file for the Web Worker
2. Move the NavmeshBuilder class and dependencies (JSTS, poly2tri) to the worker
3. Implement message passing between the main thread and worker
4. Add progress reporting from the worker

Code structure:
```javascript
// navmesh-worker.js
importScripts('jsts.min.js', 'poly2tri.min.js');

class NavmeshBuilder {
  // Existing implementation...
}

self.onmessage = async function(e) {
  const { walls, dimensions, agentRadius, taskId } = e.data;

  try {
    // Report progress
    self.postMessage({ type: 'progress', taskId, progress: 0.1, message: 'Starting navmesh generation' });

    const builder = new NavmeshBuilder();

    // Report progress at each stage
    self.postMessage({ type: 'progress', taskId, progress: 0.3, message: 'Polygonizing with JSTS' });
    const polygons = builder.polygonizeWithJSTS(walls, dimensions);

    self.postMessage({ type: 'progress', taskId, progress: 0.6, message: 'Triangulating with poly2tri' });
    const triangulation = builder.triangulateWithPoly2tri(polygons);

    self.postMessage({ type: 'progress', taskId, progress: 0.9, message: 'Formatting for three-pathfinding' });
    const navmeshData = builder.formatForThreePathfinding(triangulation);

    // Send completed navmesh back to main thread
    self.postMessage({ 
      type: 'complete', 
      taskId, 
      navmeshData,
      agentRadius 
    });
  } catch (error) {
    self.postMessage({ 
      type: 'error', 
      taskId, 
      error: error.message 
    });
  }
};

// Main thread code
class NavmeshWorkerManager {
  constructor() {
    this.worker = new Worker('navmesh-worker.js');
    this.taskCounter = 0;
    this.pendingTasks = new Map();

    this.worker.onmessage = this.handleWorkerMessage.bind(this);
  }

  handleWorkerMessage(event) {
    const { type, taskId, progress, message, navmeshData, error } = event.data;

    if (type === 'progress') {
      // Update progress UI
      this.updateProgressUI(taskId, progress, message);
    } else if (type === 'complete') {
      // Task completed successfully
      const task = this.pendingTasks.get(taskId);
      if (task) {
        task.resolve(navmeshData);
        this.pendingTasks.delete(taskId);
      }
    } else if (type === 'error') {
      // Task failed
      const task = this.pendingTasks.get(taskId);
      if (task) {
        task.reject(new Error(error));
        this.pendingTasks.delete(taskId);
      }
    }
  }

  updateProgressUI(taskId, progress, message) {
    // Update UI to show progress
    // This could be a progress bar or status message
  }

  generateNavmesh(walls, dimensions, agentRadius = 0) {
    const taskId = ++this.taskCounter;

    // Create a promise that will be resolved when the worker completes
    const promise = new Promise((resolve, reject) => {
      this.pendingTasks.set(taskId, { resolve, reject });
    });

    // Send task to worker
    this.worker.postMessage({ 
      walls, 
      dimensions, 
      agentRadius,
      taskId 
    });

    return promise;
  }
}

// Usage
const workerManager = new NavmeshWorkerManager();

async function generateNavmeshWithWorker() {
  try {
    const walls = canvas.walls.documents.filter(w => w.ds !== 2);
    const navmeshData = await workerManager.generateNavmesh(walls, canvas.dimensions);

    // Use the generated navmesh
    await game.scenes.current.setFlag('routinglib', 'navmeshData', navmeshData);
    initializePathfinding(navmeshData);
  } catch (error) {
    console.error('Navmesh generation failed:', error);
    // Handle error
  }
}
