// Update hook registration based on settings
function updateHookRegistration(mode) {
  // Unregister existing hooks
  Hooks.off('createWall', scheduleNavmeshUpdate);
  Hooks.off('updateWall', scheduleNavmeshUpdate);
  Hooks.off('deleteWall', scheduleNavmeshUpdate);

  // Register hooks based on mode
  if (mode === 'automatic') {
    Hooks.on('createWall', scheduleNavmeshUpdate);
    Hooks.on('updateWall', scheduleNavmeshUpdate);
    Hooks.on('deleteWall', scheduleNavmeshUpdate);
  } else if (mode === 'onSave') {
    Hooks.on('updateScene', (scene, changes) => {
      if (scene.id === game.scenes.current.id && !changes.flags?.routinglib?.navmeshData) {
        rebuildNavmesh();
      }
    });
  }
  // Manual mode doesn't register any hooks
}

// Function to rebuild navmesh
async function rebuildNavmesh() {
  ui.notifications.info('Rebuilding navigation mesh...');

  const startTime = performance.now();

  try {
    // Use worker for generation
    const navmeshData = await workerManager.generateNavmesh(
      canvas.walls.documents.filter(w => w.ds !== 2),
      canvas.dimensions
    );

    // Cache the result
    await game.scenes.current.setFlag('routinglib', 'navmeshData', navmeshData);

    // Initialize pathfinding
    initializePathfinding(navmeshData);

    const elapsed = performance.now() - startTime;
    ui.notifications.success(`Navigation mesh rebuilt in ${elapsed.toFixed(0)}ms`);

    // Suggest manual mode if generation is slow
    const threshold = game.settings.get('routinglib', 'performanceThreshold');
    if (elapsed > threshold && game.settings.get('routinglib', 'navmeshUpdateMode') === 'automatic') {
      suggestManualMode(elapsed);
    }
  } catch (error) {
    ui.notifications.error('Failed to rebuild navigation mesh: ' + error.message);
  }
}

// Suggest manual mode if generation is slow
function suggestManualMode(elapsed) {
  const d = new Dialog({
    title: 'Slow Navmesh Generation',
    content: `<p>Navigation mesh generation took ${elapsed.toFixed(0)}ms, which may cause UI freezing with automatic updates.</p><p>Would you like to switch to manual mode?</p>`,
    buttons: {
      yes: {
        icon: '<i class="fas fa-check"></i>',
        label: 'Switch to Manual',
        callback: () => game.settings.set('routinglib', 'navmeshUpdateMode', 'manual')
      },
      no: {
        icon: '<i class="fas fa-times"></i>',
        label: 'Keep Automatic'
      }
    }
  });
  d.render(true);
}
