class NavmeshBenchmark {
  constructor() {
    this.results = [];
  }

  async runBenchmark(testCases) {
    const results = [];

    for (const test of testCases) {
      const { name, walls, dimensions } = test;

      // Measure standard generation time
      const standardStart = performance.now();
      const builder = new NavmeshBuilder();
      await builder.buildNavmesh(walls, dimensions);
      const standardTime = performance.now() - standardStart;

      // Measure worker generation time
      const workerStart = performance.now();
      await workerManager.generateNavmesh(walls, dimensions);
      const workerTime = performance.now() - workerStart;

      results.push({
        name,
        wallCount: walls.length,
        standardTime,
        workerTime
      });
    }

    this.results = results;
    return results;
  }

  generateReport() {
    let report = '# Navmesh Generation Benchmark Results\n\n';
    report += '| Test Case | Wall Count | Standard Time (ms) | Worker Time (ms) |\n';
    report += '|-----------|------------|-------------------|-----------------|\n';

    for (const result of this.results) {
      report += `| ${result.name} | ${result.wallCount} | ${result.standardTime.toFixed(2)} | ${result.workerTime.toFixed(2)} |\n`;
    }

    return report;
  }
}

// Optimization: Cache intermediate results
class OptimizedNavmeshBuilder extends NavmeshBuilder {
  constructor() {
    super();
    this.geometryCache = new Map();
  }

  // Override polygonizeWithJSTS to use caching
  polygonizeWithJSTS(walls, dimensions) {
    // Generate a cache key based on walls and dimensions
    const cacheKey = this.generateCacheKey(walls, dimensions);

    // Check if we have a cached result
    if (this.geometryCache.has(cacheKey)) {
      return this.geometryCache.get(cacheKey);
    }

    // No cache hit, perform normal calculation
    const result = super.polygonizeWithJSTS(walls, dimensions);

    // Cache the result
    this.geometryCache.set(cacheKey, result);

    return result;
  }

  generateCacheKey(walls, dimensions) {
    // Create a hash of the walls and dimensions
    // This is a simplified version - a real implementation would need a more robust hashing function
    return JSON.stringify({
      walls: walls.map(w => w.c),
      dimensions
    });
  }

  // Clear cache when needed
  clearCache() {
    this.geometryCache.clear();
  }
}

